INSERT INTO flair_cockpit_items (id, class_name, name, description, manufacturer_id, mass, volume_scu)
VALUES
('9ea281be-4a92-47c0-acc3-c128e1f742aa', 'Flair_Dashboard_Heart_Teddy_1_a', 'Codi the Coramor Bear', 'Never fly alone with Codi the Coramor Bear. With adorable pink fur, tender faux-leather paws, and a soft belly full of love, Codi will make a faithful flight companion for your cockpit.', NULL, 0, 0.0021),
('a7c5ad04-025f-4940-9b3a-4bc33c2ff0fd', 'Flair_Hanging_Template', 'Flair_Hanging_Template', '@itemDescFlair_Vehicle', NULL, 0, 0),
('3de40834-b47a-4740-801b-b7344ef433e0', 'Flair_Dashboard_Flag_UEE_1_a', 'United Nations of Earth Mini-Flag', 'Fly the flag of the first united Human government, the United Nations of Earth (UNE). First revealed in 2380, the inaugural flag design features interlocking circles symbolizing Humanity''s three main populations centers (Earth, Mars, and Croshaw system) and six stars representing the ambition to continue expanding into space. This small metal stand flies a holographic version of the UNE flag, making it an ideal accessory for history buffs to place on their desk or aboard their ships.', '40c59850-8fb5-4a0e-ab61-7fd3871a632a', 0, 0),
('27091a02-d1d3-40ec-acd5-b2a0f3a1ca77', 'Flair_Dashboard_Bobblehead_02', 'Flair_Dashboard_Bobblehead_02', '@itemDescFlair_Vehicle', '40c59850-8fb5-4a0e-ab61-7fd3871a632a', 0, 0),
('9edbb4cd-ae1f-42e2-9884-072997d51378', 'Flair_Dashboard_Flag_UEE_1_b', 'United Planets of Earth Mini-Flag', 'This small metal stand flies a holographic flag of the United Planets of Earth (UPE). Designed in 2523 when Humanity replaced the United Nations of Earth (UNE) with a new political system better suited for its expanding governance over multiple systems. To symbolize this progression, the UPE flag kept the interlocking rings from the UNE flag while adding a circle with breaks to represent the continued desire to expand and laurel branches symbolizing the success of Humanity''s space exploration.', '40c59850-8fb5-4a0e-ab61-7fd3871a632a', 0, 0),
('88b20684-0888-444f-a805-39113fb7f6a4', 'Flair_Dashboard_Bobblehead_01', 'Flair_Dashboard_Bobblehead_01', '@itemDescFlair_Vehicle', '40c59850-8fb5-4a0e-ab61-7fd3871a632a', 0, 0),
('0da6ef02-1468-4adf-bc88-79a62a931165', 'Flair_Dashboard_Flag_UEE_1_c', 'United Empire of Earth Mini-Flag', 'Celebrate the United Empire of Earth (UEE) wherever you go by flying a holographic version of the flag. The small and sleek stands makes it an ideal accessory for a desk or ship. Featuring a vibrant blue color offset by white, this iconic symbol incorporated iconography from the previous UPE flag to represent the next phase of Humanity''s united government as it grew into a massive empire.', '40c59850-8fb5-4a0e-ab61-7fd3871a632a', 0, 0),
('727ba1fb-f426-49af-a5fe-841789d95e95', 'Flair_Hanging_Dice_01', 'Flair_Hanging_Dice_01', '@itemDescFlair_Vehicle', '40c59850-8fb5-4a0e-ab61-7fd3871a632a', 0.25, 0),
('ee4b7f25-9353-4c5f-9df2-36a109ca9e92', 'Flair_Bobble_CDS_Medium_01A', 'Sakura Fun Green ORC-mkX Armor Bobblehead', 'Like the armor set it features, the Green ORC-mkX Bobblehead is exquisitely detailed and made with high quality materials. Place Sakura Sun''s latest edition to the Sakura Fun line of bobbleheads on a ship''s dashboard for an ideal cockpit companion ready to ride along on daring space adventures.', '40c59850-8fb5-4a0e-ab61-7fd3871a632a', 0, 0),
('680911bf-f6c0-43c6-a65e-dec33e31eaa8', 'Flair_Bobble_CDS_Medium_01B', 'Sakura Fun Blue ORC-mkX Armor Bobblehead', 'Like the armor set it features, the Blue ORC-mkX Bobblehead is exquisitely detailed and made with high quality materials. Place Sakura Sun''s latest edition to the Sakura Fun line of bobbleheads on a ship''s dashboard for an ideal cockpit companion ready to ride along on daring space adventures.', '40c59850-8fb5-4a0e-ab61-7fd3871a632a', 0, 0),
('2b88b0eb-d7da-4894-a702-3767fa8327b8', 'Flair_Bobble_CDS_Medium_01C', 'Sakura Fun White ORC-mkX Armor Bobblehead', 'Like the armor set it features, the White ORC-mkX Bobblehead is exquisitely detailed and made with high quality materials. Place Sakura Sun''s latest edition to the Sakura Fun line of bobbleheads on a ship''s dashboard for an ideal cockpit companion ready to ride along on daring space adventures.', '40c59850-8fb5-4a0e-ab61-7fd3871a632a', 0, 0)
